import{c as a,Q as s,j as t,m as e}from"./chunks/framework.Bhbi9jCp.js";const h=JSON.parse('{"title":"苹果原生开发系列写作计划","description":"","frontmatter":{},"headers":[],"relativePath":"iosNativeLearning/00-写作计划.md","filePath":"iosNativeLearning/00-写作计划.md","lastUpdated":1779789238000}'),i={name:"iosNativeLearning/00-写作计划.md"};function o(p,n,l,d,r,c){return s(),t("div",null,[...n[0]||(n[0]=[e(`<h1 id="苹果原生开发系列写作计划" tabindex="-1">苹果原生开发系列写作计划 <a class="header-anchor" href="#苹果原生开发系列写作计划" aria-label="Permalink to &quot;苹果原生开发系列写作计划&quot;">​</a></h1><blockquote><p>基线版本:<strong>iOS 18 (API 18.0) / Swift 6 / Xcode 16 / SwiftUI</strong>(2026/05 时点;iOS 19 新 API 涉及到时单独标注)。 不做&quot;SwiftUI 控件展览&quot;,不做&quot;Objective-C 复刻&quot;,不做&quot;跨端选型对比&quot;。</p></blockquote><hr><h2 id="一句话定位" tabindex="-1">一句话定位 <a class="header-anchor" href="#一句话定位" aria-label="Permalink to &quot;一句话定位&quot;">​</a></h2><p><strong>让一个会写代码、但没怎么写过 iOS 的人,用 Swift 6 + SwiftUI 把一款能上 App Store 的现代 iOS 应用做出来。</strong></p><p>读者画像:已经熟悉一门主流语言(Go / Kotlin / TS / Python 都行),写过其他平台或跨端 App,但被 Swift Concurrency、<code>@Observable</code>、SwiftData、严格并发的选择劝退过。</p><hr><h2 id="统一心智-贯穿-27-章" tabindex="-1">统一心智(贯穿 27 章) <a class="header-anchor" href="#统一心智-贯穿-27-章" aria-label="Permalink to &quot;统一心智(贯穿 27 章)&quot;">​</a></h2><blockquote><p><strong>现代 iOS 是一棵被 Observation 追踪的 SwiftUI 视图树,挂在 <code>App</code> 协议入口上,被 Swift Concurrency 隔离并发,被 SwiftData 落盘,通过 Apple 平台框架接入系统能力。剩下的一切——Widget、推送、StoreKit、Core ML——都是这棵树的扩展或副作用边界。</strong></p></blockquote><p>这句话压住全场,后面 27 章都是它的推论:</p><ul><li><strong>&quot;一棵 SwiftUI 视图树&quot;</strong> → 05-10 篇,View / 状态 / 布局 / Modifier / 动画 / 手势</li><li><strong>&quot;被 Observation 追踪&quot;</strong> → 06 篇 <code>@Observable</code> 字段级 diff</li><li><strong>&quot;挂在 <code>App</code> 协议入口&quot;</strong> → 01 / 02 篇,<code>@main App</code> 取代 <code>AppDelegate</code></li><li><strong>&quot;被 Swift Concurrency 隔离并发&quot;</strong> → 04 篇 <code>async/actor/Sendable</code></li><li><strong>&quot;被 SwiftData 落盘&quot;</strong> → 12 篇 <code>@Model</code> + <code>ModelContainer</code> + <code>@Query</code></li><li><strong>&quot;系统能力是树的扩展或副作用边界&quot;</strong> → 15-22 篇</li></ul><p>如果哪一篇没法挂在这棵树上,这一篇就不该出现。</p><hr><h2 id="_27-章地图" tabindex="-1">27 章地图 <a class="header-anchor" href="#_27-章地图" aria-label="Permalink to &quot;27 章地图&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>心智(1 章)</span></span>
<span class="line"><span>  01  原生 iOS 的一张地图</span></span>
<span class="line"><span></span></span>
<span class="line"><span>地基(3 章)</span></span>
<span class="line"><span>  02  Xcode 项目骨架与 xcconfig</span></span>
<span class="line"><span>  03  Swift 6 类型系统</span></span>
<span class="line"><span>  04  Swift Concurrency 与 Sendable</span></span>
<span class="line"><span></span></span>
<span class="line"><span>SwiftUI 一族(6 章)</span></span>
<span class="line"><span>  05  View 协议、声明式与 @State</span></span>
<span class="line"><span>  06  Observation 与状态流向</span></span>
<span class="line"><span>  07  布局:Stack、Grid 与 Layout 协议</span></span>
<span class="line"><span>  08  Modifier 链与样式系统</span></span>
<span class="line"><span>  09  动画与共享元素</span></span>
<span class="line"><span>  10  手势与冲突</span></span>
<span class="line"><span></span></span>
<span class="line"><span>架构与闭环(4 章)</span></span>
<span class="line"><span>  11  NavigationStack 路由</span></span>
<span class="line"><span>  12  SwiftData 与 CloudKit</span></span>
<span class="line"><span>  13  URLSession 与网络层</span></span>
<span class="line"><span>  14  Keychain 与 App Group</span></span>
<span class="line"><span></span></span>
<span class="line"><span>系统能力(5 章)</span></span>
<span class="line"><span>  15  UIKit 与 Objective-C 互操作</span></span>
<span class="line"><span>  16  推送与 APNs</span></span>
<span class="line"><span>  17  AVFoundation 与 PhotoKit</span></span>
<span class="line"><span>  18  权限与 Privacy Manifest</span></span>
<span class="line"><span>  19  后台任务与 App Intents</span></span>
<span class="line"><span></span></span>
<span class="line"><span>平台特色与体验(4 章)</span></span>
<span class="line"><span>  20  Widget 与 Live Activities</span></span>
<span class="line"><span>  21  StoreKit 2 与 Sign in with Apple</span></span>
<span class="line"><span>  22  端侧 AI:Core ML 与 Vision</span></span>
<span class="line"><span>  23  Accessibility 与本地化</span></span>
<span class="line"><span></span></span>
<span class="line"><span>工程化与发布(4 章)</span></span>
<span class="line"><span>  24  SwiftUI 性能与重渲染追踪</span></span>
<span class="line"><span>  25  Instruments 与 MetricKit</span></span>
<span class="line"><span>  26  SPM 模块化与测试体系</span></span>
<span class="line"><span>  27  签名、TestFlight 与上架</span></span></code></pre></div><p><strong>优先级</strong>:01-14 每篇都建议看;15-19 按需(做什么功能看什么);20-27 上架前必看。</p><hr><h2 id="默认技术选择" tabindex="-1">默认技术选择 <a class="header-anchor" href="#默认技术选择" aria-label="Permalink to &quot;默认技术选择&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>选择</th><th>一句话理由</th></tr></thead><tbody><tr><td>最低部署目标</td><td>iOS 18</td><td>2026/05 装机量甜点位,iOS 19+ API 单独标注</td></tr><tr><td>主语言</td><td>Swift 6,strict concurrency</td><td>数据竞争编译期消灭,贴近 Apple 未来方向</td></tr><tr><td>UI 框架</td><td>SwiftUI + <code>@Observable</code></td><td>不写 Storyboard / XIB / <code>ObservableObject</code></td></tr><tr><td>并发</td><td><code>async/await</code> + <code>actor</code> + <code>Sendable</code></td><td>GCD 仅作对比心智</td></tr><tr><td>数据持久化</td><td>SwiftData,Core Data 仅作 fallback</td><td>iOS 17+ 推荐路径,<code>@Model</code> 几行替代几十行</td></tr><tr><td>云同步</td><td>CloudKit 直挂 <code>@Model</code></td><td>不接 Firebase / 自建后端</td></tr><tr><td>网络</td><td><code>URLSession.data(for:)</code> async + <code>Codable</code></td><td>不装 Alamofire,不写 Combine</td></tr><tr><td>三方依赖</td><td>默认零,SPM 按需加</td><td>空工程最长寿</td></tr><tr><td>测试</td><td>Swift Testing + XCTest UI</td><td><code>@Test</code> / <code>#expect</code> 取代 <code>XCTAssert*</code></td></tr><tr><td>发布</td><td>App Store + TestFlight</td><td>不做企业签名 / AltStore</td></tr></tbody></table><p><strong>不覆盖</strong>:跨端见 [[flutterLearning]];协议栈见 [[networkLearning]];AI 模型本身见 [[aiLearning]];OWASP / 越狱见 [[securityLearning]]。</p><hr><h2 id="持续演进的样例应用-notesisland" tabindex="-1">持续演进的样例应用:NotesIsland <a class="header-anchor" href="#持续演进的样例应用-notesisland" aria-label="Permalink to &quot;持续演进的样例应用:NotesIsland&quot;">​</a></h2><p>整个系列共享一个样例应用 <strong>NotesIsland</strong>(本地优先 + iCloud 同步的笔记 App,带图片、录音、Widget、Live Activities、订阅),从第 05 篇起逐章长大。</p><p>这套功能恰好覆盖一个真实 iOS 应用的所有关键面:本地持久化 + 云同步、SwiftUI UI、录音 / 选图、推送、Widget / Live Activities、StoreKit 订阅、端侧 AI。比 To-Do 更接近真实,比社交 App 又不被业务细节带偏。</p><p><strong>但 NotesIsland 不是每篇都重提</strong>——它是一根挂代码的线,不是主角。心智才是主角。多数代码示例是独立片段,跑得通就够;不强求拼成同一个 Xcode 工程。</p><hr><h2 id="写作风格-强约束" tabindex="-1">写作风格(强约束) <a class="header-anchor" href="#写作风格-强约束" aria-label="Permalink to &quot;写作风格(强约束)&quot;">​</a></h2><ol><li>每篇开篇一句话压上核心 claim,不超 40 字。</li><li>章节标题用「一、二、三」,<strong>不用</strong>「机制定位 / Apple 平台心智 / 调参与验收」这种学究腔。</li><li>段落不超过 150 字,长段落必拆。</li><li>强观点直接说。读者要的是判断,不是百科。</li><li>表格只用于真正需要对比的地方,不堆砌。</li><li>每篇结尾留一段&quot;踩坑&quot;,对应一个真实事故场景,不写&quot;建议注意&quot;这种废话。</li><li>不写多余的&quot;小结&quot;和&quot;过渡段&quot;。代码片段 30-80 行,不再塞 90+ 行的&quot;最小骨架&quot;。</li></ol><hr><h2 id="与旧版本的差异" tabindex="-1">与旧版本的差异 <a class="header-anchor" href="#与旧版本的差异" aria-label="Permalink to &quot;与旧版本的差异&quot;">​</a></h2><p>旧版 30 篇 / 1.6 万行,问题:标题就是 API 罗列(<code>@Binding 与 @Environment 与 @Entry 与数据流向</code>)、机械五段式模板、单篇均长 530 行(对照 git 系列 300 行)、第一篇先做销售文案、代码块过长。 新版 27 篇,把 03/04/05(类型 + 并发 + actor)合到 03/04 两篇,把 07/08(<code>@Observable</code> + <code>@Binding/@Environment</code>)合到 06 一篇,把 28/29(SPM + 测试)合到 26 一篇。Accessibility 单独成 23,因为是上架硬要求;SwiftUI 性能(24)与 Instruments(25)分开,因为前者是渲染心智,后者是工具链,合篇容易乱。</p>`,31)])])}const S=a(i,[["render",o]]);export{h as __pageData,S as default};
